          {"\u05d1\u05dc\u05d7\u05e9: \u05d1\u05b8\u05bc\u05e8\u05d5\u05bc\u05da\u05b0 \u05e9\u05b5\u05c1\u05dd \u05db\u05b0\u05bc\u05d1\u05d5\u05b9\u05d3 \u05de\u05b7\u05dc\u05b0\u05db\u05d5\u05bc\u05ea\u05d5\u05b9 \u05dc\u05b0\u05e2\u05d5\u05b9\u05dc\u05b8\u05dd \u05d5\u05b8\u05e2\u05b6\u05d3:"}
